  ('social-worker-moex-01171', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究者想了解社會工作師對個案的關心程度，決定以計算訪視及電話關懷次數作為補充性佐證資 料，此種資料蒐集方式是下列何者？', '["問卷訪談", "非干擾性的測量", "實驗設計", "質性訪談"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
