  ('social-worker-moex-01173', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於質性研究資料分析的特質，下列何者錯誤？', '["焦點在於現象的意義", "對於資料有深入的詮釋", "強調預先設定好的資料分類", "強調研究者本身是重要的研究分析工具"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01174', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列何者屬於紮根理論方法資料分析的必要步驟？', '["歸納出現的次數", "討論符號與其意義", "整合不同類屬", "預設類屬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01175', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某位學者希望探討社工員的替代性創傷經驗，因此寄信給相關機構兒少保社工員，詳細說明研究 內容，並透過書面文件簽署以確認其參與意願，此做法主要是回應下列那項研究倫理議題？', '["欺騙和隱瞞", "隱私與保密", "告知後同意", "互惠的關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01176', 'social-worker', 'social-worker-moex-110-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '為了追蹤離院返家兒童的調適狀況，研究人員設計問卷量表，聯絡這些人進行個別電訪，並在撰 寫報告時僅呈現樣本加總後的整體數據，這份報告呈現的方式符合下列那種敘述？', '["既不匿名也不保密", "匿名但不保密", "保密但不匿名", "匿名且保密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "b103121a72fe", "answer_pdf_sha1": "6d5b6600baad", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01177', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'essay', '社會工作專業在臺灣雖已獲得社會的肯定，但如何面對社會各界對服務
績效與品質的訴求，是社會工作專業後續發展必須面對的議題。請分別
回答下列問題：績效管理之「績效監測」（performancemonitoring）的
意涵及其實施步驟為何？社會服務組織該如何回應社會各界對社會
服務品質的訴求？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01178', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'essay', '晚近社會工作發展強調公民參與、網絡信任、利益共享等價值，這些理
念逐漸促成「最佳價值」（bestvalue）制度及強調公私夥伴關係共同治理
模式。請說明：「最佳價值」的內涵與特色為何？其對社會工作實務的影
響為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01179', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', 'Frederick Herzberg所提出的雙因子理論（motivation-hygiene theory）是激勵的重要理論，下列有 關雙因子理論之敘述，何者錯誤？', '["管理者在激勵員工時，要先區隔保健因子跟激勵因子的不同", "工作滿足的反面是工作不滿足", "保健因子主要是跟工作環境有關，激勵因子主要是跟工作成就感有關", "提供保健因子主要是滿足員工的基本需求，提供激勵因子才可以滿足員工的高層次需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01180', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '新管理主義（new managerialism）是一種對專業權力的挑戰，著重管理、績效評鑑及效能，下列 對於新管理主義的敘述何者錯誤？', '["強調公共服務的集體化與去分散化，以提升公共服務供給者間的競爭", "強調服務使用者對服務供給者的選擇權與發言權", "強調買方與賣方分離之契約化服務供給模式", "降低政治決策對公共服務管理的直接干預"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "5eb261e734f1", "answer_pdf_sha1": "0af20b0ec580", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
